DROP DATABASE IF EXISTS dark_pattern_detection;
CREATE DATABASE dark_pattern_detection;
USE dark_pattern_detection;
CREATE TABLE dark_patterns (
  `id` TEXT,
  `page_text` TEXT,
  `urgency_words` TEXT,
  `popup_count` TEXT,
  `price_difference` TEXT,
  `button_highlight` TEXT,
  `pattern_label` TEXT
);
USE dark_pattern_detection;

SELECT COUNT(*) AS Total_Records
FROM dark_patterns;

SELECT * FROM dark_patterns
LIMIT 10;

SELECT pattern_label, COUNT(*)
FROM dark_patterns
GROUP BY pattern_label;